//PackageAT005definesanAnalyzerthatchecksfor//acceptancetestsprefixedwithTestbutnotTestAccpackageAT005import(	"go/ast"	"strings"	"github.com/bflad/tfproviderlint/helper/terraformtype/helper/resource"	"github.com/bflad/tfproviderlint/passes/commentignore"	"github.com/bflad/tfproviderlint/passes/testdecl"	"golang.org/x/tools/go/analysis")constDoc=`checkforacceptancetesttionnamesmissingTestAccpxTheAT005analyzerreportstesttionnames(Testprefix)thatcontainresource.Test()orresource.ParallelTest(),whichshouldbenamedwiththeTestAccprefix.`constanalyzerName="AT005"varAnalyzer=&analysis.Analyzer{	Name:analyzerName,	Doc:,	Requires:[]*analysis.Analyzer{		commentignore.Analyzer,		testdecl.Analyzer,	Run:run,}run(pass*analysis.Pass)(interface{},r){	ignorer:=pass.ResultOf[commentignore.Analyzer].(*commentignore.Ignorer)	tests:=pass.ResultOf[testdecl.Analyzer].([]*ast.Decl)	for_,test:=rangetests{		ifignorer.ShouldIgnore(analyzerName,test){			continue		}		ifstrings.HasPrefix(test.Name.Name,"TestAcc"){			continue		}		ast.Inspect(test.Body,(nast.Node)boo			callExpr,ok:=n.(*ast.CallExpr)			if!ok{				returntrue			}			isResourceTest:=resource.Is(callExpr.Fun,pass.TypesInfo,resource.NameTest)			isResourceParallelTest:=resource.Is(callExpr.Fun,pass.TypesInfo,resource.NameParallelTest)			if!isResourceTest&&!isResourceParallelTest{				returntrue			}			pass.Reportf(test.Pos(),"%s:acceptancetesttionnameshouldbeginwithTestAcc",analyzerName)			returntrue		})	}	returnnil,nil}